'use client'

import { useEffect, useState, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import gsap from 'gsap'
import { playThud, playGlitch, playChime, playWhoosh, playLetterThud } from '@/lib/sounds'

const LETTERS = ['R', 'E', 'V', 'O', 'L', 'Q']

export default function Preloader() {
  const [show, setShow] = useState(false)
  const [phase, setPhase] = useState(0)
  const containerRef = useRef<HTMLDivElement>(null)
  const lettersRef = useRef<(HTMLSpanElement | null)[]>([])
  const lineRef = useRef<SVGLineElement>(null)
  const subTextRef = useRef<HTMLDivElement>(null)
  const audioCtxRef = useRef<AudioContext | null>(null)

  useEffect(() => {
    if (typeof window === 'undefined') return

    // Check sessionStorage
    const hasLoaded = sessionStorage.getItem('revolq_loaded')
    if (hasLoaded) {
      setShow(false)
      return
    }

    setShow(true)

    // Create AudioContext
    try {
      audioCtxRef.current = new AudioContext()
    } catch {
      // Audio not supported
    }

    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches

    if (prefersReducedMotion) {
      // Skip all animations
      setTimeout(() => {
        sessionStorage.setItem('revolq_loaded', 'true')
        setShow(false)
      }, 500)
      return
    }

    // Phase 1: Blackout (0ms to 800ms)
    setPhase(1)
    if (audioCtxRef.current) {
      playThud(audioCtxRef.current)
    }

    // Phase 2: Glitch burst (800ms)
    setTimeout(() => {
      setPhase(2)
      // Play 3 rapid glitch clicks
      if (audioCtxRef.current) {
        for (let i = 0; i < 3; i++) {
          setTimeout(() => {
            if (audioCtxRef.current) playGlitch(audioCtxRef.current)
          }, i * 80)
        }
      }

      // Shake the R letter
      const rLetter = lettersRef.current[0]
      if (rLetter) {
        gsap.to(rLetter, {
          x: '+=8',
          y: '+=4',
          duration: 0.05,
          repeat: 6,
          yoyo: true,
          ease: 'none',
        })
      }
    }, 800)

    // Phase 3: Letter build (1400ms)
    setTimeout(() => {
      setPhase(3)
      lettersRef.current.forEach((el, i) => {
        if (!el) return
        gsap.fromTo(
          el,
          {
            y: -80,
            opacity: 0,
            filter: 'blur(20px)',
          },
          {
            y: 0,
            opacity: 1,
            filter: 'blur(0px)',
            duration: 0.5,
            delay: i * 0.12,
            ease: 'power3.out',
          }
        )
        // Play letter thud
        if (audioCtxRef.current) {
          setTimeout(() => {
            if (audioCtxRef.current) playLetterThud(audioCtxRef.current, i)
          }, i * 120)
        }
      })
    }, 1400)

    // Phase 4: Breathe (2600ms)
    setTimeout(() => {
      setPhase(4)

      // Breathe animation
      const letterContainer = containerRef.current?.querySelector('.preloader-letters')
      if (letterContainer) {
        gsap.to(letterContainer, {
          scale: 1.02,
          duration: 0.3,
          yoyo: true,
          repeat: 1,
          ease: 'sine.inOut',
        })
      }

      // Line draw
      if (lineRef.current) {
        gsap.fromTo(
          lineRef.current,
          { strokeDashoffset: 1 },
          { strokeDashoffset: 0, duration: 0.5, ease: 'power2.inOut' }
        )
      }

      // Sub text fade
      if (subTextRef.current) {
        gsap.fromTo(
          subTextRef.current,
          { opacity: 0 },
          { opacity: 1, duration: 0.4, delay: 0.2 }
        )
      }

      // Chime sound
      if (audioCtxRef.current) {
        playChime(audioCtxRef.current)
      }
    }, 2600)

    // Phase 5: Explosion exit (3200ms)
    setTimeout(() => {
      setPhase(5)

      const letterContainer = containerRef.current?.querySelector('.preloader-letters')
      if (letterContainer) {
        gsap.to(letterContainer, {
          scale: 8,
          opacity: 0,
          duration: 0.6,
          ease: 'power4.in',
        })
      }

      if (containerRef.current) {
        gsap.to(containerRef.current, {
          clipPath: 'circle(150% at 50% 50%)',
          duration: 0.8,
          ease: 'power3.inOut',
        })
      }

      if (audioCtxRef.current) {
        playWhoosh(audioCtxRef.current)
      }

      setTimeout(() => {
        sessionStorage.setItem('revolq_loaded', 'true')
        setShow(false)
      }, 900)
    }, 3200)
  }, [])

  if (!show) return null

  return (
    <AnimatePresence>
      {show && (
        <motion.div
          initial={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 0.4 }}
        >
          <div
            ref={containerRef}
            className="preloader"
            style={{
              clipPath: phase >= 5 ? 'circle(0% at 50% 50%)' : 'circle(150% at 50% 50%)',
            }}
          >
            {/* Phase 2: Flash effects */}
            {phase === 2 && (
              <div
                style={{
                  position: 'absolute',
                  inset: 0,
                  animation: 'flicker 0.15s steps(3) 3',
                }}
              />
            )}

            {/* Letters */}
            <div className="preloader-letters" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              {LETTERS.map((letter, i) => (
                <span
                  key={letter}
                  ref={(el) => { lettersRef.current[i] = el }}
                  className="preloader-letter"
                  style={{
                    opacity: phase < 3 ? (phase === 2 && i === 0 ? 1 : 0) : 1,
                    fontSize: phase === 2 && i === 0 ? '30vw' : '18vw',
                    textShadow:
                      phase === 2 && i === 0
                        ? '-4px 0 rgba(255,0,0,0.7), 4px 0 rgba(0,255,255,0.7)'
                        : phase === 3
                          ? `-${Math.max(0, 3 - i)}px 0 rgba(255,0,0,0.3), ${Math.max(0, 3 - i)}px 0 rgba(0,255,255,0.3)`
                          : 'none',
                  }}
                >
                  {letter}
                </span>
              ))}
            </div>

            {/* Phase 4: Line and subtitle */}
            {phase >= 4 && (
              <div
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  marginTop: '1rem',
                }}
              >
                <svg width="40vw" height="2" viewBox="0 0 100 2" style={{ maxWidth: '500px' }}>
                  <line
                    ref={lineRef}
                    x1="0"
                    y1="1"
                    x2="100"
                    y2="1"
                    stroke="var(--rose)"
                    strokeWidth="0.5"
                    strokeDasharray="1"
                    strokeDashoffset="1"
                    pathLength="1"
                  />
                </svg>
                <div
                  ref={subTextRef}
                  className="text-label"
                  style={{
                    marginTop: '1rem',
                    opacity: 0,
                    letterSpacing: '0.5em',
                  }}
                >
                  DIGITAL AGENCY · KERALA · INDIA
                </div>
              </div>
            )}
          </div>

          <style jsx>{`
            @keyframes flicker {
              0% { background: transparent; }
              33% { background: rgba(255,255,255,0.9); }
              66% { background: transparent; }
              100% { background: rgba(255,255,255,0.5); }
            }
          `}</style>
        </motion.div>
      )}
    </AnimatePresence>
  )
}

'use client'

import { useEffect, useRef } from 'react'
import Image from 'next/image'
import gsap from 'gsap'
import { ScrollTrigger } from 'gsap/ScrollTrigger'
import { Code, Search, Cpu, PenLine, Layers, RefreshCw } from 'lucide-react'
import SplitText from '@/components/ui/SplitText'

gsap.registerPlugin(ScrollTrigger)

const icons = [Code, Search, Cpu, PenLine, Layers, RefreshCw]

const services = [
  {
    num: '01',
    title: 'WEB DEVELOPMENT',
    desc: 'Next.js websites engineered to rank, convert, and scale. Not templates. Not themes. Systems.',
    tags: ['Next.js', 'TypeScript', 'Vercel', 'SEO-first'],
    img: 'https://images.unsplash.com/photo-1555066931-4365d14431b9?auto=format&fit=crop&w=800&q=80',
  },
  {
    num: '02',
    title: 'SEO & GBP',
    desc: 'Google visibility for businesses that deserve to be found. Local SEO, Search Console, structured data, monthly ranking reports.',
    tags: ['Google', 'Search Console', 'GBP', 'Schema'],
    img: 'https://images.unsplash.com/photo-1432888498266-38ffec3eaf0a?auto=format&fit=crop&w=800&q=80',
  },
  {
    num: '03',
    title: 'AI AUTOMATION',
    desc: 'WhatsApp agents that reply in your voice. n8n workflows that run while you sleep. Your business, automated.',
    tags: ['Claude AI', 'n8n', 'WhatsApp API', 'Webhooks'],
    img: 'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?auto=format&fit=crop&w=800&q=80',
  },
  {
    num: '04',
    title: 'CONTENT & COPY',
    desc: 'Words that convert. Descriptions that rank. Copy that makes visitors become clients.',
    tags: ['SEO Copy', 'Brand Voice', 'OG', 'Schema'],
    img: 'https://images.unsplash.com/photo-1455390582262-044cdead277a?auto=format&fit=crop&w=800&q=80',
  },
  {
    num: '05',
    title: 'BRAND STRATEGY',
    desc: 'Positioning. Identity. The story your business tells before anyone speaks.',
    tags: ['Identity', 'Positioning', 'Visual System'],
    img: 'https://images.unsplash.com/photo-1634942537034-2531766767d1?auto=format&fit=crop&w=800&q=80',
  },
  {
    num: '06',
    title: 'MONTHLY RETAINER',
    desc: 'We become your digital team. GBP management, content, SEO monitoring, AI maintenance — all handled. Every month.',
    tags: ['Ongoing', 'Reports', 'Management', 'Growth'],
    img: 'https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&w=800&q=80',
  },
]

export default function Services() {
  const sectionRef = useRef<HTMLDivElement>(null)
  const scrollContainerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (!sectionRef.current || !scrollContainerRef.current) return

    const totalScroll = scrollContainerRef.current.scrollWidth - window.innerWidth

    const tween = gsap.to(scrollContainerRef.current, {
      x: -totalScroll,
      ease: 'none',
      scrollTrigger: {
        trigger: sectionRef.current,
        start: 'top top',
        end: `+=${totalScroll}`,
        scrub: 1,
        pin: true,
        anticipatePin: 1,
      },
    })

    return () => {
      tween.kill()
      ScrollTrigger.getAll().forEach((st) => {
        if (st.trigger === sectionRef.current) st.kill()
      })
    }
  }, [])

  return (
    <section ref={sectionRef} style={{ overflow: 'hidden', position: 'relative' }}>
      <div
        ref={scrollContainerRef}
        style={{
          display: 'flex',
          alignItems: 'stretch',
          height: '100vh',
        }}
      >
        {/* Pinned left panel */}
        <div
          style={{
            minWidth: 'clamp(300px, 30vw, 500px)',
            padding: 'clamp(2rem, 5vh, 4rem) clamp(1.5rem, 5vw, 4rem)',
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
            borderRight: '1px solid var(--border)',
          }}
        >
          <span className="text-label" style={{ marginBottom: '1.5rem' }}>
            WHAT WE DO
          </span>
          <SplitText text="Every system." className="text-h2" tag="h2" />
          <SplitText text="Carefully built." className="text-h2" delay={0.1} tag="h2" />
          <p className="text-body" style={{ marginTop: '1.5rem', maxWidth: 280 }}>
            Six services. One agency.
          </p>
        </div>

        {/* Cards */}
        {services.map((service, i) => {
          const Icon = icons[i]
          return (
            <div
              key={service.num}
              style={{
                minWidth: 420,
                height: '100%',
                padding: '3rem 2.5rem',
                borderRight: '1px solid var(--border)',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'space-between',
                position: 'relative',
                overflow: 'hidden',
              }}
            >
              {/* Number */}
              <span className="text-mono" style={{ opacity: 0.4, marginBottom: '1rem' }}>
                {service.num}
              </span>

              {/* Icon + Title */}
              <div>
                <Icon
                  size={24}
                  strokeWidth={1}
                  color="var(--rose)"
                  style={{ marginBottom: '1rem' }}
                />
                <h3
                  style={{
                    fontFamily: 'var(--font-body)',
                    fontSize: '0.65rem',
                    fontWeight: 300,
                    letterSpacing: '0.3em',
                    color: 'var(--white)',
                    marginBottom: '1rem',
                  }}
                >
                  {service.title}
                </h3>
                <p className="text-body" style={{ fontSize: '0.85rem', maxWidth: 320 }}>
                  {service.desc}
                </p>
              </div>

              {/* Tags */}
              <div
                style={{
                  display: 'flex',
                  flexWrap: 'wrap',
                  gap: '0.5rem',
                  margin: '1.5rem 0',
                }}
              >
                {service.tags.map((tag) => (
                  <span
                    key={tag}
                    className="text-mono"
                    style={{
                      padding: '0.3rem 0.6rem',
                      border: '1px solid var(--border)',
                      borderRadius: '2px',
                      fontSize: '0.6rem',
                    }}
                  >
                    {tag}
                  </span>
                ))}
              </div>

              {/* Image */}
              <div style={{ position: 'relative', aspectRatio: '16/10', width: '100%', borderRadius: '4px', overflow: 'hidden' }}>
                <Image
                  src={service.img}
                  alt={service.title}
                  fill
                  style={{ objectFit: 'cover', opacity: 0.6 }}
                  sizes="420px"
                />
              </div>
            </div>
          )
        })}
      </div>
    </section>
  )
}

'use client'

import { useEffect, useRef } from 'react'
import * as THREE from 'three'

const vertexShader = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = vec4(position, 1.0);
  }
`

const fragmentShader = `
  precision highp float;
  uniform float uTime;
  uniform float uScroll;
  uniform vec2 uMouse;
  uniform vec2 uResolution;
  varying vec2 vUv;

  // Simplex noise helpers
  vec3 mod289(vec3 x) { return x - floor(x * (1.0/289.0)) * 289.0; }
  vec4 mod289(vec4 x) { return x - floor(x * (1.0/289.0)) * 289.0; }
  vec4 permute(vec4 x) { return mod289(((x*34.0)+1.0)*x); }
  vec4 taylorInvSqrt(vec4 r) { return 1.79284291400159 - 0.85373472095314 * r; }

  float snoise(vec3 v) {
    const vec2 C = vec2(1.0/6.0, 1.0/3.0);
    const vec4 D = vec4(0.0, 0.5, 1.0, 2.0);
    vec3 i = floor(v + dot(v, C.yyy));
    vec3 x0 = v - i + dot(i, C.xxx);
    vec3 g = step(x0.yzx, x0.xyz);
    vec3 l = 1.0 - g;
    vec3 i1 = min(g.xyz, l.zxy);
    vec3 i2 = max(g.xyz, l.zxy);
    vec3 x1 = x0 - i1 + C.xxx;
    vec3 x2 = x0 - i2 + C.yyy;
    vec3 x3 = x0 - D.yyy;
    i = mod289(i);
    vec4 p = permute(permute(permute(
      i.z + vec4(0.0, i1.z, i2.z, 1.0))
      + i.y + vec4(0.0, i1.y, i2.y, 1.0))
      + i.x + vec4(0.0, i1.x, i2.x, 1.0));
    float n_ = 0.142857142857;
    vec3 ns = n_ * D.wyz - D.xzx;
    vec4 j = p - 49.0 * floor(p * ns.z * ns.z);
    vec4 x_ = floor(j * ns.z);
    vec4 y_ = floor(j - 7.0 * x_);
    vec4 x = x_ * ns.x + ns.yyyy;
    vec4 y = y_ * ns.x + ns.yyyy;
    vec4 h = 1.0 - abs(x) - abs(y);
    vec4 b0 = vec4(x.xy, y.xy);
    vec4 b1 = vec4(x.zw, y.zw);
    vec4 s0 = floor(b0)*2.0 + 1.0;
    vec4 s1 = floor(b1)*2.0 + 1.0;
    vec4 sh = -step(h, vec4(0.0));
    vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy;
    vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww;
    vec3 p0 = vec3(a0.xy, h.x);
    vec3 p1 = vec3(a0.zw, h.y);
    vec3 p2 = vec3(a1.xy, h.z);
    vec3 p3 = vec3(a1.zw, h.w);
    vec4 norm = taylorInvSqrt(vec4(dot(p0,p0),dot(p1,p1),dot(p2,p2),dot(p3,p3)));
    p0 *= norm.x; p1 *= norm.y; p2 *= norm.z; p3 *= norm.w;
    vec4 m = max(0.6 - vec4(dot(x0,x0),dot(x1,x1),dot(x2,x2),dot(x3,x3)), 0.0);
    m = m * m;
    return 42.0 * dot(m*m, vec4(dot(p0,x0),dot(p1,x1),dot(p2,x2),dot(p3,x3)));
  }

  void main() {
    vec2 uv = vUv;
    float t = uTime * 0.15;

    // Mouse-reactive UV offset
    vec2 mouseOffset = (uMouse - 0.5) * 0.08;
    uv += mouseOffset;

    // 4-layer simplex noise
    float n1 = snoise(vec3(uv * 1.5, t)) * 0.5;
    float n2 = snoise(vec3(uv * 3.0 + 10.0, t * 1.3)) * 0.25;
    float n3 = snoise(vec3(uv * 5.0 + 20.0, t * 0.8)) * 0.125;
    float n4 = snoise(vec3(uv * 8.0 + 30.0, t * 1.6)) * 0.0625;
    float noise = n1 + n2 + n3 + n4;

    // Scroll-reactive color palette shift
    float scrollShift = uScroll * 0.3;

    // 5 color zones
    vec3 colA = vec3(0.02, 0.02, 0.04); // deep ink
    vec3 colB = vec3(0.42, 0.37, 0.66); // violet
    vec3 colC = vec3(0.77, 0.60, 0.60); // rose
    vec3 colD = vec3(0.83, 0.69, 0.44); // gold
    vec3 colE = vec3(0.94, 0.93, 0.96); // white

    float colorPos = noise * 0.5 + 0.5 + scrollShift;
    colorPos = mod(colorPos, 1.0);

    vec3 color;
    if (colorPos < 0.25) {
      color = mix(colA, colB, colorPos * 4.0);
    } else if (colorPos < 0.5) {
      color = mix(colB, colC, (colorPos - 0.25) * 4.0);
    } else if (colorPos < 0.75) {
      color = mix(colC, colD, (colorPos - 0.5) * 4.0);
    } else {
      color = mix(colD, colE, (colorPos - 0.75) * 4.0);
    }

    // Scale down the brightness significantly
    color *= 0.18;

    // Glowing horizontal band that moves with scroll
    float band = smoothstep(0.05, 0.0, abs(uv.y - mod(uScroll * 0.5 + t * 0.3, 1.4) + 0.2)) * 0.12;
    color += vec3(band * 0.77, band * 0.60, band * 0.60);

    // Subtle grid lines
    float gridX = smoothstep(0.98, 1.0, sin(uv.x * 40.0 + t) * 0.5 + 0.5) * 0.02;
    float gridY = smoothstep(0.98, 1.0, sin(uv.y * 40.0 + t * 0.7) * 0.5 + 0.5) * 0.02;
    color += vec3(gridX + gridY) * vec3(0.42, 0.37, 0.66);

    // Vignette
    float vig = 1.0 - smoothstep(0.3, 1.2, length(vUv - 0.5) * 1.4);
    color *= vig;

    gl_FragColor = vec4(color, 1.0);
  }
`

export default function AuroraBackground() {
  const containerRef = useRef<HTMLDivElement>(null)
  const mouseRef = useRef({ x: 0.5, y: 0.5 })
  const scrollRef = useRef(0)

  useEffect(() => {
    if (!containerRef.current) return

    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches
    if (prefersReducedMotion) return

    const scene = new THREE.Scene()
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1)
    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: false })
    renderer.setSize(window.innerWidth, window.innerHeight)
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 1.5))
    containerRef.current.appendChild(renderer.domElement)

    const uniforms = {
      uTime: { value: 0 },
      uScroll: { value: 0 },
      uMouse: { value: new THREE.Vector2(0.5, 0.5) },
      uResolution: { value: new THREE.Vector2(window.innerWidth, window.innerHeight) },
    }

    const geometry = new THREE.PlaneGeometry(2, 2)
    const material = new THREE.ShaderMaterial({
      vertexShader,
      fragmentShader,
      uniforms,
    })
    const mesh = new THREE.Mesh(geometry, material)
    scene.add(mesh)

    // Floating orbs
    const orbGeometry = new THREE.SphereGeometry(0.3, 16, 16)
    const orbMaterial = new THREE.MeshBasicMaterial({
      color: 0x6b5fa8,
      transparent: true,
      opacity: 0.04,
    })
    const orbs: THREE.Mesh[] = []
    for (let i = 0; i < 3; i++) {
      const orb = new THREE.Mesh(orbGeometry, orbMaterial.clone())
      orb.position.set(
        (Math.random() - 0.5) * 4,
        (Math.random() - 0.5) * 4,
        -2
      )
      scene.add(orb)
      orbs.push(orb)
    }

    // Particles
    const particleCount = 180
    const particlePositions = new Float32Array(particleCount * 3)
    for (let i = 0; i < particleCount; i++) {
      particlePositions[i * 3] = (Math.random() - 0.5) * 6
      particlePositions[i * 3 + 1] = (Math.random() - 0.5) * 6
      particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 4 - 1
    }
    const particleGeometry = new THREE.BufferGeometry()
    particleGeometry.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3))
    const particleMaterial = new THREE.PointsMaterial({
      size: 0.008,
      color: 0xd8d4e8,
      transparent: true,
      opacity: 0.4,
      sizeAttenuation: true,
    })
    const particles = new THREE.Points(particleGeometry, particleMaterial)
    scene.add(particles)

    // Create perspective camera for particles
    const perspCam = new THREE.PerspectiveCamera(50, window.innerWidth / window.innerHeight, 0.1, 100)
    perspCam.position.z = 3

    const handleMouseMove = (e: MouseEvent) => {
      mouseRef.current = {
        x: e.clientX / window.innerWidth,
        y: 1 - e.clientY / window.innerHeight,
      }
    }

    const handleScroll = () => {
      const docHeight = document.documentElement.scrollHeight - window.innerHeight
      scrollRef.current = docHeight > 0 ? window.scrollY / docHeight : 0
    }

    const handleResize = () => {
      renderer.setSize(window.innerWidth, window.innerHeight)
      uniforms.uResolution.value.set(window.innerWidth, window.innerHeight)
      perspCam.aspect = window.innerWidth / window.innerHeight
      perspCam.updateProjectionMatrix()
    }

    window.addEventListener('mousemove', handleMouseMove)
    window.addEventListener('scroll', handleScroll, { passive: true })
    window.addEventListener('resize', handleResize)

    let animId: number
    const animate = () => {
      animId = requestAnimationFrame(animate)
      uniforms.uTime.value += 0.016
      uniforms.uScroll.value = scrollRef.current
      uniforms.uMouse.value.set(mouseRef.current.x, mouseRef.current.y)

      // Animate orbs
      orbs.forEach((orb, i) => {
        orb.position.x += Math.sin(uniforms.uTime.value * 0.3 + i * 2) * 0.002
        orb.position.y += Math.cos(uniforms.uTime.value * 0.2 + i * 3) * 0.002
      })

      // Camera parallax
      perspCam.position.x += (mouseRef.current.x * 0.5 - 0.25 - perspCam.position.x) * 0.02
      perspCam.position.y += (mouseRef.current.y * 0.5 - 0.25 - perspCam.position.y) * 0.02

      // Render fullscreen shader with ortho cam
      renderer.autoClear = true
      renderer.render(scene, camera)
    }

    animate()

    return () => {
      cancelAnimationFrame(animId)
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('scroll', handleScroll)
      window.removeEventListener('resize', handleResize)
      renderer.dispose()
      geometry.dispose()
      material.dispose()
      orbGeometry.dispose()
      particleGeometry.dispose()
      if (containerRef.current) {
        containerRef.current.removeChild(renderer.domElement)
      }
    }
  }, [])

  return (
    <div
      ref={containerRef}
      className="aurora-canvas"
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 0,
      }}
    />
  )
}

'use client'

import { useEffect, useRef, useState } from 'react'
import gsap from 'gsap'

export default function Cursor() {
  const dotRef = useRef<HTMLDivElement>(null)
  const ringRef = useRef<HTMLDivElement>(null)
  const [isHovering, setIsHovering] = useState(false)
  const [hoverText, setHoverText] = useState('')
  const mouse = useRef({ x: 0, y: 0 })
  const ringPos = useRef({ x: 0, y: 0 })

  useEffect(() => {
    const isTouchDevice = 'ontouchstart' in window || navigator.maxTouchPoints > 0
    if (isTouchDevice) return

    const handleMove = (e: MouseEvent) => {
      mouse.current = { x: e.clientX, y: e.clientY }
      if (dotRef.current) {
        dotRef.current.style.transform = `translate(${e.clientX - 3}px, ${e.clientY - 3}px)`
      }
    }

    const handleOver = (e: MouseEvent) => {
      const target = e.target as HTMLElement
      const link = target.closest('a, button, [data-cursor]')
      if (link) {
        setIsHovering(true)
        const cursorText = link.getAttribute('data-cursor') || ''
        setHoverText(cursorText)
      }
    }

    const handleOut = (e: MouseEvent) => {
      const target = e.target as HTMLElement
      const link = target.closest('a, button, [data-cursor]')
      if (link) {
        setIsHovering(false)
        setHoverText('')
      }
    }

    const tick = () => {
      ringPos.current.x += (mouse.current.x - ringPos.current.x) * 0.12
      ringPos.current.y += (mouse.current.y - ringPos.current.y) * 0.12
      if (ringRef.current) {
        const size = isHovering ? 64 : 40
        ringRef.current.style.transform = `translate(${ringPos.current.x - size / 2}px, ${ringPos.current.y - size / 2}px)`
      }
      requestAnimationFrame(tick)
    }

    window.addEventListener('mousemove', handleMove)
    document.addEventListener('mouseover', handleOver)
    document.addEventListener('mouseout', handleOut)
    const raf = requestAnimationFrame(tick)

    return () => {
      window.removeEventListener('mousemove', handleMove)
      document.removeEventListener('mouseover', handleOver)
      document.removeEventListener('mouseout', handleOut)
      cancelAnimationFrame(raf)
    }
  }, [isHovering])

  return (
    <div id="cursor">
      <div
        ref={dotRef}
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: 6,
          height: 6,
          borderRadius: '50%',
          background: 'var(--rose)',
          pointerEvents: 'none',
          zIndex: 9998,
          mixBlendMode: 'difference',
          opacity: isHovering ? 0 : 1,
          transition: 'opacity 0.2s ease',
        }}
      />
      <div
        ref={ringRef}
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: isHovering ? 64 : 40,
          height: isHovering ? 64 : 40,
          borderRadius: '50%',
          border: `1px solid var(--rose)`,
          pointerEvents: 'none',
          zIndex: 9997,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          transition: 'width 0.3s ease, height 0.3s ease',
        }}
      >
        {hoverText && (
          <span
            style={{
              fontFamily: 'var(--font-mono)',
              fontSize: 8,
              color: 'var(--rose)',
              letterSpacing: '0.1em',
            }}
          >
            {hoverText}
          </span>
        )}
      </div>
    </div>
  )
}
